/**
 * Export vulnerabilities with progress tracking.
 *
 * Polling strategy:
 * - 1s for the first 5 polls (catch fast "starting" transitions)
 * - 2s for the next 10 polls
 * - 5s thereafter, up to a 10s cap
 *
 * Stall detection:
 * - If processedItems AND currentStage are unchanged for STALL_WARN_SEC,
 *   onStall(job, stalledSec) is invoked so the UI can warn the user.
 * - If they're unchanged for STALL_ABORT_SEC we throw (no infinite wait).
 *
 * All poll results are console.logged (namespaced "[export {shortId}]") so
 * the browser devtools give a full timeline of what the backend reported.
 */
const STALL_WARN_SEC = 60;
const STALL_ABORT_SEC = 15 * 60;

function chooseInterval(pollCount: number): number {
    if (pollCount < 5) return 1000;
    if (pollCount < 15) return 2000;
    if (pollCount < 60) return 5000;
    return 10000;
}

export interface ExportVulnerabilitiesOptions {
    onProgress?: (update: ExportProgressUpdate) => void;
    onStall?: (update: ExportProgressUpdate) => void;
}

