/**
 * Download all vulnerability exceptions as a JSON file.
 * Triggers a browser download. Returns nothing on success.
 */
export async function exportAllExceptions(): Promise<void> {
    const response = await authenticatedGet('/api/vulnerability-exceptions/export');
    if (!response.ok) {
        throw new Error(`Export failed: HTTP ${response.status}`);
    }
    const disposition = response.headers.get('Content-Disposition') ?? '';
    const match = disposition.match(/filename="?([^"]+)"?/);
    const filename = match ? match[1] : `vulnerability-exceptions-${Date.now()}.json`;
    const blob = await response.blob();
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
}

/**
 * Upload a JSON file to the import endpoint. Returns the per-row result.
 */
export async function importExceptions(file: File): Promise<ExceptionImportResult> {
    const form = new FormData();
    form.append('file', file);
    const response = await authenticatedPost('/api/vulnerability-exceptions/import', form);
    if (!response.ok) {
        const body = await response.text();
        throw new Error(`Import failed: HTTP ${response.status} ${body}`);
    }
    return response.json();
}

